import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT;

        // Call the focal method
        CSVFormat result = format.withAllowMissingColumnNames(true);

        // Verify that a new instance is returned (immutability)
        assertNotNull(result);
        assertNotSame(format, result);

        // The allowMissingColumnNames flag should be true in the new instance
        assertTrue(result.getAllowMissingColumnNames());

        // The original instance should remain unchanged
        assertFalse(format.getAllowMissingColumnNames());
    }
}
